example.code:
using var workbook = ExcelDocument.Create("report.xlsx");
var sheet = workbook.Sheets[0];
sheet.AddImageFromFile(2, 2, "logo.png", scalePercent: 20, name: "Logo", altText: "Company logo");
workbook.Save();

using var workbook = ExcelDocument.Create("report.xlsx");
var sheet = workbook.Sheets[0];
byte[] logo = File.ReadAllBytes("logo.png");
sheet.AddImageToRange("A1:C15", logo, "image/png", name: "PinnedLogo",
    altText: "Company logo", placement: ExcelImagePlacement.MoveAndSize);
workbook.Save();

member.example:
// Internal: link "Domain" column to same-named sheets, rows 2..used bottom
sheet.LinkByHeaderToInternalSheets("Domain");
// External: link "RFC" column to IETF datatracker pages
sheet.LinkByHeaderToUrls("RFC", urlForCellText: rfc => $"https://datatracker.ietf.org/doc/html/{rfc}");

member.param:
Controls how invalid table names are handled:
             (default) replaces invalid characters and adjusts the name;
             throws descriptive exceptions for invalid names.
